#include <stdio.h>

// Define structure with tag name 'Student'
struct Student {
 char name[30]; // Character array for name
 int rollNo; // Integer for roll number
 float marks; // Float for marks
};

int main() {
 // Declare structure variable
 struct Student s1;

 // Initialize using member access operator
 s1.rollNo = 101;
 s1.marks = 85.5;

 // For string, use strcpy
 // strcpy(s1.name, "John Doe");

 // Access and display members
 printf("Roll No: %d\n", s1.rollNo);
 printf("Marks: %.2f\n", s1.marks);

 // Initialize at declaration
 struct Student s2 = {102, "Alice", 90.0};

 return 0;
}

#include <stdio.h>

// Define inner structure first
struct Date {
 int day;
 int month;
 int year;
};

// Define outer structure containing Date
struct Employee {
 char name[50];
 int empId;
 struct Date birthDate; // Nested structure member
 struct Date joiningDate; // Another nested member
};

int main() {
 // Declare and initialize nested structure
 struct Employee emp = {
 "John Smith",
 1001,
 {15, 8, 1990}, // Initialize birthDate
 {1, 3, 2020} // Initialize joiningDate
 };

 // Access nested members using chained dot operator
 printf("Employee: %s\n", emp.name);
 printf("Birth Date: %d/%d/%d\n", 
 emp.birthDate.day,
 emp.birthDate.month,
 emp.birthDate.year);
 printf("Joining Date: %d/%d/%d\n",
 emp.joiningDate.day,
 emp.joiningDate.month,
 emp.joiningDate.year);

 return 0;
}

#include <stdio.h>

// Using typedef to create alias 'Point' for the structure
typedef struct {
 int x; // X-coordinate
 int y; // Y-coordinate
} Point;

// Another example with tag
typedef struct {
 char name[30];
 float salary;
} Employee;

int main() {
 // Declare variables WITHOUT using 'struct' keyword
 Point p1 = {10, 20};
 Point p2;

 p2.x = 30;
 p2.y = 40;

 Employee emp1 = {"Alice", 50000.0};

 // Access members normally
 printf("Point 1: (%d, %d)\n", p1.x, p1.y);
 printf("Point 2: (%d, %d)\n", p2.x, p2.y);
 printf("Employee: %s, Salary: %.2f\n", 
 emp1.name, emp1.salary);

 // Can also create arrays and pointers
 Point points[5];
 Point *ptr = &p1;

 return 0;
}
